package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import com.google.gson.JsonObject;
import com.google.gson.JsonPrimitive;
import com.google.gson.JsonElement;
import java.lang.reflect.Field;

public class JsonObjectEqualsTest {

  @Test
  public void testEquals_sameReference() {
    JsonObject obj = new JsonObject();
    assertTrue(obj.equals(obj));
  }

  @Test
  public void testEquals_null() {
    JsonObject obj = new JsonObject();
    assertFalse(obj.equals(null));
  }

  @Test
  public void testEquals_differentClass() {
    JsonObject obj = new JsonObject();
    String other = "not a JsonObject";
    assertFalse(obj.equals(other));
  }

  @Test
  public void testEquals_emptyObjects() {
    JsonObject obj1 = new JsonObject();
    JsonObject obj2 = new JsonObject();
    assertTrue(obj1.equals(obj2));
    assertTrue(obj2.equals(obj1));
  }

  @Test
  public void testEquals_sameMembers() throws Exception {
    JsonObject obj1 = new JsonObject();
    JsonObject obj2 = new JsonObject();

    JsonPrimitive prim = new JsonPrimitive("value");

    obj1.addProperty("key", "value");
    obj2.addProperty("key", "value");

    // Verify equals returns true
    assertTrue(obj1.equals(obj2));
    assertTrue(obj2.equals(obj1));
  }

  @Test
  public void testEquals_differentMembers() throws Exception {
    JsonObject obj1 = new JsonObject();
    JsonObject obj2 = new JsonObject();

    obj1.addProperty("key1", "value1");
    obj2.addProperty("key2", "value2");

    assertFalse(obj1.equals(obj2));
    assertFalse(obj2.equals(obj1));
  }

  @Test
  public void testEquals_membersWithDifferentValues() throws Exception {
    JsonObject obj1 = new JsonObject();
    JsonObject obj2 = new JsonObject();

    obj1.addProperty("key", "value1");
    obj2.addProperty("key", "value2");

    assertFalse(obj1.equals(obj2));
    assertFalse(obj2.equals(obj1));
  }
}
